CustomField.formula:
IF(ISBLANK(Empfaenger__r.Account.IBAN__c), "",
    UPPER(
        /* 1. Block: Stellen 1-4 (z.B. AE82) */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 1, 4) + " " +

        /* 2. Block: Stellen 5-8 */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 5, 4) + " " +

        /* 3. Block: Stellen 9-12 */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 9, 4) + " " +

        /* 4. Block: Stellen 13-16 */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 13, 4) + " " +

        /* 5. Block: Stellen 17-20 */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 17, 4) + " " +

        /* 6. Block: Der Rest (Stellen 21-24) */
        MID(SUBSTITUTE(Empfaenger__r.Account.IBAN__c, " ", ""), 21, 4)
    )
)
